export function getExtendedSignName(id: string): string | null {
  const key = id.trim().toUpperCase();
  if (!key) return null;
  if (EXTENDED_SIGN_MAP[key]) return EXTENDED_SIGN_MAP[key];

  const candidates = new Set<string>();
  if (!key.startsWith("US")) {
    if (/^S\d/.test(key)) {
      candidates.add(`US${key.slice(1)}`);
    }
    candidates.add(`US${key}`);
  } else {
    candidates.add(key.slice(2));
  }

  for (const candidate of candidates) {
    const match = EXTENDED_SIGN_MAP[candidate];
    if (match) return match;
  }
  return null;
}

export function hasExtendedSign(id: string): boolean {
  return Boolean(getExtendedSignName(id));
}
